import numpy as np
from collections import Counter

class Vocabulary:
    SPECIAL_TOKENS = ['<pad>', '<unk>', '<bos>', '<eos>']

    def __init__(self, min_freq: int = 1):
        self.min_freq = min_freq
        self.word2idx = {}
        self.idx2word = {}

    def build(self, corpus: list) -> 'Vocabulary':
        all_tokens = []
        for sentence in corpus:
            all_tokens.extend(sentence.lower().split())

        counts = Counter(all_tokens)
        filtered = {w: c for w, c in counts.items() if c >= self.min_freq}

        # Sort by frequency desc, then alphabetically
        sorted_words = sorted(filtered.keys(), key=lambda w: (-filtered[w], w))

        self.word2idx = {t: i for i, t in enumerate(self.SPECIAL_TOKENS)}
        for word in sorted_words:
            self.word2idx[word] = len(self.word2idx)

        self.idx2word = {i: w for w, i in self.word2idx.items()}
        return self

    def encode(self, sentence: str) -> list:
        unk_id = self.word2idx['<unk>']
        return [self.word2idx.get(t, unk_id) for t in sentence.lower().split()]

    def decode(self, ids: list) -> list:
        return [self.idx2word.get(i, '<unk>') for i in ids]

    def __len__(self):
        return len(self.word2idx)

